// Attach chunk-level metadata before embedding
return $input.all().map((item, i) => ({
  json: {
    ...item.json,
    chunkIndex: i,
    sourceUrl: item.json.sourceUrl || item.json.url || 'internal',
    ingestedAt: new Date().toISOString(),
  },
}));

// Build a stable idempotency key per document (djb2 hash, no deps)
function hash(s) {
  let h = 5381;
  for (let i = 0; i < s.length; i++) h = ((h << 5) + h + s.charCodeAt(i)) >>> 0;
  return h.toString(16);
}
return $input.all().map(item => {
  const j = item.json;
  return { json: { ...j, idempotencyKey: hash([j.docId, j.title].join('|')) } };
});
